document.querySelectorAll(".carousel-container").forEach(e=>{const n=e.querySelectorAll(".carousel-item");let t=0;function s(e){n.forEach((t,n)=>t.style.display=n===e?"block":"none")}s(t);const i=e.querySelector(".carousel-prev"),a=e.querySelector(".carousel-next");i.addEventListener("click",()=>{t=(t-1+n.length)%n.length,s(t)}),a.addEventListener("click",()=>{t=(t+1)%n.length,s(t)});let o=0;e.addEventListener("touchstart",e=>o=e.touches[0].clientX),e.addEventListener("touchend",e=>{let i=e.changedTouches[0].clientX-o;i>50?(t=(t-1+n.length)%n.length,s(t)):i<-50&&(t=(t+1)%n.length,s(t))})})